#### 4. 更新 package.json 脚本

```json
{
  "scripts": {
    "build": "tsc",
    "start": "npm run build && node dist/main.js",
    "dev": "ts-node src/main.ts",
    "check": "node dist/main.js --check",
    "auto": "npm run build && node dist/main.js --auto",
    "auto:test": "npm run build && node dist/main.js --auto --max 1",

    // 🆕 新增脚本
    "config:validate": "ts-node src/scripts/validate-config.ts",
    "config:init": "cp .env.example .env",
    "prestart": "npm run config:validate",
    "preauto": "npm run config:validate"
  }
