```

#### 5. 创建配置验证脚本

```typescript
// src/scripts/validate-config.ts
import { loadConfig } from '../config/loader';
import chalk from 'chalk';

function validateConfig() {
  console.log(chalk.blue('🔍 验证项目配置...\n'));

  try {
    const config = loadConfig();

    console.log(chalk.green('✅ 配置验证通过！\n'));
    console.log(chalk.gray('当前配置:'));
    console.log(JSON.stringify(config, null, 2));

    // 检查项目路径是否存在
    const fs = require('fs');
    if (!fs.existsSync(config.PROJECT_PATH)) {
      console.log(chalk.yellow(`\n⚠️  警告: 项目路径不存在: ${config.PROJECT_PATH}`));
    } else {
      console.log(chalk.green(`\n✅ 项目路径验证通过`));
    }

    process.exit(0);
  } catch (error) {
    if (error instanceof Error) {
      console.error(chalk.red(`\n❌ ${error.message}\n`));

      if (error.message.includes('配置验证失败')) {
        console.log(chalk.yellow('💡 提示: 运行 npm run config:init 创建配置文件'));
      }
    }
    process.exit(1);
  }
}

validateConfig();
```

#### 6. 创建启动前的健康检查

```typescript
// src/scripts/health-check.ts
import { getConfig } from '../config/loader';
import chalk from 'chalk';
import fs from 'fs';
import { execSync } from 'child_process';

export function healthCheck() {
  const config = getConfig();
  const issues: string[] = [];

  // 检查 API Token
  if (!config.ANTHROPIC_AUTH_TOKEN || config.ANTHROPIC_AUTH_TOKEN === 'your_api_token_here') {
    issues.push('❌ ANTHROPIC_AUTH_TOKEN 未设置');
  } else {
    console.log(chalk.green('✅ API Token 已配置'));
  }

  // 检查项目路径
  if (!fs.existsSync(config.PROJECT_PATH)) {
    issues.push(`❌ 项目路径不存在: ${config.PROJECT_PATH}`);
  } else {
    console.log(chalk.green(`✅ 项目路径: ${config.PROJECT_PATH}`));

    // 检查是否是 Git 仓库
    try {
      execSync('git rev-parse --git-dir', { cwd: config.PROJECT_PATH, stdio: 'pipe' });
      console.log(chalk.green('✅ Git 仓库验证通过'));
    } catch {
      issues.push('⚠️  项目路径不是 Git 仓库');
    }
  }

  // 检查 Dashboard 端口
  if (config.DASHBOARD_ENABLED) {
    console.log(chalk.blue(`ℹ️  Dashboard 将在端口 ${config.DASHBOARD_PORT} 启动`));
  }

  if (issues.length > 0) {
    console.log(chalk.red('\n⚠️  发现以下问题:'));
    issues.forEach(issue => console.log(chalk.red(issue)));
    console.log(chalk.yellow('\n请修复这些问题后再启动\n'));
    return false;
  }

  console.log(chalk.green('\n✅ 所有检查通过，可以启动！\n'));
  return true;
}
```

---

### 📦 需要安装的依赖

```bash
npm install zod chalk
npm install -D @types/node
```

---

### ✅ 验收标准

1. ✅ 运行 `npm run config:init` 自动创建 `.env` 文件
2. ✅ 运行 `npm run config:validate` 验证配置是否正确
3. ✅ 配置错误时显示友好的错误提示
4. ✅ 启动前自动进行健康检查
5. ✅ `.env.example` 提供完整的配置说明

---

### 🎁 收益

| 收益 | 描述 |
|:-----|:-----|
| **提高稳定性** | 配置错误在启动前就能发现 |
| **改善体验** | 新用户快速了解需要配置什么 |
| **减少调试** | 清晰的错误提示节省调试时间 |
| **文档化** | `.env.example` 本身就是配置文档 |

---

