```typescript
// src/services/websocket.ts

export class DashboardWebSocket {
  private ws: WebSocket | null = null;
  private reconnectAttempts = 0;
  private maxReconnectAttempts = 5;

  connect() {
    this.ws = new WebSocket('ws://localhost:3000/api/ws');

    this.ws.onopen = () => {
      console.log('✅ WebSocket connected');
      this.reconnectAttempts = 0;

      // 启动心跳
      this.startHeartbeat();
    };

    this.ws.onmessage = (event) => {
      const { event: eventName, data } = JSON.parse(event.data);

      // 路由事件到相应的 store
      switch (eventName) {
        case 'iteration.started':
          useIterationStore().onIterationStarted(data);
          break;
        case 'agent.status_changed':
          useAgentStore().onAgentStatusChanged(data);
          break;
        case 'iteration.progress':
          useIterationStore().onProgressUpdate(data);
          break;
        case 'system.metrics':
          useSystemStore().onMetricsUpdate(data);
          break;
      }
    };

    this.ws.onerror = () => {
      console.error('❌ WebSocket error');
    };

    this.ws.onclose = () => {
      console.log('🔌 WebSocket closed');
      this.reconnect();
    };
  }

  private reconnect() {
    if (this.reconnectAttempts < this.maxReconnectAttempts) {
      this.reconnectAttempts++;
      setTimeout(() => this.connect(), 2000 * this.reconnectAttempts);
    }
  }

  private startHeartbeat() {
    setInterval(() => {
      this.ws?.send(JSON.stringify({ event: 'ping' }));
    }, 30000);
  }
}
