// 分页 + 游标
async listIterations(params: {
  limit?: number;
  cursor?: string;
  status?: string;
}) {
  const { limit = 20, cursor, status } = params;

  let query = db('iterations')
    .where('is_deleted', false)
    .orderBy('started_at', 'desc')
    .limit(limit);

  if (status) {
    query = query.where('status', status);
  }

  if (cursor) {
    query = query.where('started_at', '<', cursor);
  }

  const results = await query;

  return {
    data: results,
    nextCursor: results.length === limit 
      ? results[results.length - 1].started_at 
      : null
  };
}
