// 消息去重 + 批量发送
export class MessageBatcher {
  private buffer: Map<string, any> = new Map();
  private timer?: NodeJS.Timeout;

  add(event: string, data: any) {
    const key = `${event}:${JSON.stringify(data)}`;
    this.buffer.set(key, { event, data });

    if (!this.timer) {
      this.timer = setTimeout(() => this.flush(), 100);
    }
  }

  private flush() {
    const messages = Array.from(this.buffer.values());
    this.buffer.clear();
    this.timer = undefined;

    // 批量发送
    this.ws?.send(JSON.stringify({
      type: 'batch',
      messages
    }));
  }
}
