import { FastifyInstance } from 'fastify';
import { IterationService } from '../services/iteration.service';

export async function iterationRoutes(fastify: FastifyInstance, iterationService: IterationService) {

  // 获取迭代列表
  fastify.get('/api/iterations', async (request, reply) => {
    const { page = 1, limit = 20, status } = request.query as any;

    const result = iterationService.getList({
      page: parseInt(page),
      limit: parseInt(limit),
      filter: status ? { status } : undefined,
    });

    return result;
  });

  // 获取迭代详情
  fastify.get('/api/iterations/:id', async (request, reply) => {
    const { id } = request.params as { id: string };
    const detail = iterationService.getDetail(parseInt(id));

    if (!detail) {
      reply.code(404).send({ error: 'Iteration not found' });
      return;
    }

    return detail;
  });

  // 获取迭代统计
  fastify.get('/api/iterations/stats/overview', async (request, reply) => {
    const { days = 30 } = request.query as { days?: string };
    return iterationService.getStats(parseInt(days) || 30);
  });

  // 获取当前运行的迭代
  fastify.get('/api/iterations/current', async (request, reply) => {
    const current = iterationService.findRunning();
    return current || { message: 'No running iteration' };
  });
}
